Write tests for this function:

function calculateShippingCost(order) {
  if (!order.items || order.items.length === 0) return 0;
  const weight = order.items.reduce((sum, item) => sum + item.weight * item.quantity, 0);
  if (order.destination === 'domestic') {
    if (weight < 1) return 5.99;
    if (weight < 5) return 9.99;
    return 14.99 + Math.ceil((weight - 5) / 5) * 4.99;
  }
  if (order.destination === 'international') {
    return weight * 12.99;
  }
  throw new Error(`Unknown destination: ${order.destination}`);
}
